def solve(nums: Array[Long], queries: Array[Array[Long]]): Long = {
   val MOD = 1000000007L
   for (query <- queries) {
      val li = query(0).toLong
      val ri = query(1).toLong
      val ki = query(2).toLong
      val vi = query(3).toLong
      var idx = li
      while (idx <= ri) {
         nums(idx.toInt) = (nums(idx.toInt) * vi) % MOD
         idx += ki
      }
   }
   var xor = 0L
   for (num <- nums) {
      xor ^= num
   }
   xor
}
